def query_es(query):
    # Query Elasticsearch for relevant documents based on the user's query
    search = es.search(index="company_docs", body={"query": {"multi_match": {"query": query, "fields": ["title^2", "content"]}}})
    return search['hits']['hits']

def generate_response(docs):
    # Tokenize and encode documents using the tokenizer
    encoded_docs = [tokenizer.encode_plus(doc["_source"]["content"], add_special_tokens=True, return_tensors='pt') for doc in docs]

    # Encode user query and concatenate it with the encoded documents
    encoded_input = tokenizer.encode_plus(input="user: " + query + "\n\n" + "\n\n".join([tokenizer.convert_ids_to_tokens(doc) for doc in encoded_docs]), add_special_tokens=True, return_tensors='pt')

    # Generate response using the model given the input
    outputs = model.generate(**encoded_input, max_length=1024, pad_token_id=tokenizer.pad_token_id)

    # Decode the generated response and return it
    return tokenizer.decode(outputs[0][len(encoded_input["input_ids"]):])

def main():
    # Load documents, vectorize them, and save to Elasticsearch (or any suitable database)
    load_documents("company_docs", "documents")
    vectorize_docs("company_docs", "documents")

    while True:
        query = input("Enter your question: ")
        docs = query_es(query)
        response = generate_response(docs)
        print(f"Assistant's response:\n{response}")

if __name__ == "__main__":
    main()